package com.example.bookservice.controller;import com.example.bookservice.exception.ExceptionController;import com.example.bookservice.exception.HttpStatusException;import com.example.bookservice.model.Review;import com.example.bookservice.model.ReviewAdminStatsDto;import com.example.bookservice.model.ReviewBookStatsDto;import com.example.bookservice.service.ReviewService;import com.fasterxml.jackson.databind.ObjectMapper;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.http.HttpStatus;import org.springframework.http.MediaType;import org.springframework.test.web.servlet.MockMvc;import org.springframework.test.web.servlet.setup.MockMvcBuilders;import java.time.LocalDateTime;import java.util.ArrayList;import java.util.Collections;import java.util.List;import static org.mockito.ArgumentMatchers.any;import static org.mockito.ArgumentMatchers.anyLong;import static org.mockito.Mockito.*;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;@ExtendWith(MockitoExtension.class)class ReviewControllerTest {  private MockMvc mockMvc;  private ObjectMapper objectMapper;  @Mock private ReviewService reviewService;  @InjectMocks private ReviewController reviewController;  private Review review;  @BeforeEach  void setUp() {    objectMapper = new ObjectMapper();    objectMapper.findAndRegisterModules();    mockMvc =        MockMvcBuilders.standaloneSetup(reviewController)            .setControllerAdvice(new ExceptionController())            .build();    review = new Review();    review.setId(1L);    review.setAuthor("user1");    review.setBookName("Book1");    review.setRating(5);    review.setComment("Отличная книга!");    review.setCreatedAt(LocalDateTime.now());  }  @Test  void createReview_ReturnCreated() throws Exception {    doNothing().when(reviewService).addReview(any(Review.class));    mockMvc        .perform(            post("/reviews")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(review)))        .andExpect(status().isCreated());  }  @Test  void createReview_ReturnConflictWithUser() throws Exception {    doThrow(new HttpStatusException(HttpStatus.CONFLICT, "Вы уже оставили отзыв на книгу Book1"))        .when(reviewService)        .addReview(any(Review.class));    mockMvc        .perform(            post("/reviews")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(review)))        .andExpect(status().isConflict())        .andExpect(jsonPath("$.message").value("Вы уже оставили отзыв на книгу Book1"));  }  @Test  void createReview_ReturnConflictWithBook() throws Exception {    doThrow(new HttpStatusException(HttpStatus.CONFLICT, "Книга с названием Book1 не существует!"))        .when(reviewService)        .addReview(any(Review.class));    mockMvc        .perform(            post("/reviews")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(review)))        .andExpect(status().isConflict())        .andExpect(jsonPath("$.message").value("Книга с названием Book1 не существует!"));  }  @Test  void createReview_ReturnBadRequestUserNotOwner() throws Exception {    doThrow(            new HttpStatusException(                HttpStatus.BAD_REQUEST, "Вы не обладаете книгой с названием Book1"))        .when(reviewService)        .addReview(any(Review.class));    mockMvc        .perform(            post("/reviews")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(review)))        .andExpect(status().isBadRequest())        .andExpect(jsonPath("$.message").value("Вы не обладаете книгой с названием Book1"));  }  @Test  void createReview_ReturnConflictElse() throws Exception {    doThrow(new HttpStatusException(HttpStatus.CONFLICT, "Не удалось сохранить отзыв!"))        .when(reviewService)        .addReview(any(Review.class));    mockMvc        .perform(            post("/reviews")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(review)))        .andExpect(status().isConflict())        .andExpect(jsonPath("$.message").value("Не удалось сохранить отзыв!"));  }  @Test  void createReview_ReturnBadRequestInvalidInput() throws Exception {    Review invalidReview = new Review();    mockMvc        .perform(            post("/reviews")                .contentType(MediaType.APPLICATION_JSON)                .content(objectMapper.writeValueAsString(invalidReview)))        .andExpect(status().isBadRequest());  }  @Test  void getReviewsByLogin_ReturnListOfReviews() throws Exception {    List<Review> reviews = Collections.singletonList(review);    when(reviewService.getReviewsByAuthor("user1")).thenReturn(reviews);    mockMvc        .perform(get("/reviews/user/user1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L))        .andExpect(jsonPath("$[0].author").value("user1"))        .andExpect(jsonPath("$[0].bookName").value("Book1"))        .andExpect(jsonPath("$[0].rating").value(5))        .andExpect(jsonPath("$[0].comment").value("Отличная книга!"));  }  @Test  void getReviewsByLogin_ReturnEmptyArray() throws Exception {    when(reviewService.getReviewsByAuthor("user1")).thenReturn(new ArrayList<>());    mockMvc        .perform(get("/reviews/user/user1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$").isArray())        .andExpect(jsonPath("$").isEmpty());  }  @Test  void getReviewsByBook_ReturnListOfReviews() throws Exception {    List<Review> reviews = Collections.singletonList(review);    when(reviewService.getReviewsById(1L)).thenReturn(reviews);    mockMvc        .perform(get("/reviews/book/1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L))        .andExpect(jsonPath("$[0].bookName").value("Book1"));  }  @Test  void getReviewsByBook_ReturnNotFound() throws Exception {    when(reviewService.getReviewsById(1L))        .thenThrow(new HttpStatusException(HttpStatus.NOT_FOUND, "Книга с id = 1 не найдена!"));    mockMvc        .perform(get("/reviews/book/1"))        .andExpect(status().isNotFound())        .andExpect(jsonPath("$.message").value("Книга с id = 1 не найдена!"));  }  @Test  void getReviewsByBook_ReturnEmptyArray() throws Exception {    when(reviewService.getReviewsById(1L)).thenReturn(new ArrayList<>());    mockMvc        .perform(get("/reviews/book/1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$").isArray())        .andExpect(jsonPath("$").isEmpty());  }  @Test  void getLastReviews_ReturnListOfReviews() throws Exception {    List<Review> reviews = Collections.singletonList(review);    when(reviewService.getReviewsByDescCreatedAt()).thenReturn(reviews);    mockMvc        .perform(get("/reviews/last"))        .andExpect(status().isOk())        .andExpect(jsonPath("$[0].id").value(1L));  }  @Test  void getLastReviews_ReturnEmptyArray() throws Exception {    when(reviewService.getReviewsByDescCreatedAt()).thenReturn(new ArrayList<>());    mockMvc        .perform(get("/reviews/last"))        .andExpect(status().isOk())        .andExpect(jsonPath("$").isArray())        .andExpect(jsonPath("$").isEmpty());  }  @Test  void getReviewAdminStats_ReturnStats() throws Exception {    ReviewAdminStatsDto statsDto = new ReviewAdminStatsDto(10L, 5L, 1L);    when(reviewService.getReviewStatsForAdmin()).thenReturn(statsDto);    mockMvc        .perform(get("/reviews/stats"))        .andExpect(status().isOk())        .andExpect(jsonPath("$.countReviews").value(10L))        .andExpect(jsonPath("$.countRate5").value(5L))        .andExpect(jsonPath("$.countRate1").value(1L));  }  @Test  void getReviewBookStats_ReturnStats() throws Exception {    ReviewBookStatsDto statsDto = new ReviewBookStatsDto(4.5, 10);    when(reviewService.getReviewStatsAboutBook(1L)).thenReturn(statsDto);    mockMvc        .perform(get("/reviews/stats/1"))        .andExpect(status().isOk())        .andExpect(jsonPath("$.avgRating").value(4.5))        .andExpect(jsonPath("$.countRating").value(10));  }  @Test  void getReviewBookStats_ReturnNotFound() throws Exception {    when(reviewService.getReviewStatsAboutBook(1L))        .thenThrow(new HttpStatusException(HttpStatus.NOT_FOUND, "Книга с id = 1 не найдена!"));    mockMvc        .perform(get("/reviews/stats/1"))        .andExpect(status().isNotFound())        .andExpect(jsonPath("$.message").value("Книга с id = 1 не найдена!"));  }  @Test  void deleteReview_ReturnNoContent() throws Exception {    doNothing().when(reviewService).deleteReview(anyLong());    mockMvc.perform(delete("/reviews/1")).andExpect(status().isNoContent());  }  @Test  void deleteReview_ReturnNotFound() throws Exception {    doThrow(new HttpStatusException(HttpStatus.NOT_FOUND, "Отзыв с id 1 не найден!"))        .when(reviewService)        .deleteReview(anyLong());    mockMvc        .perform(delete("/reviews/1"))        .andExpect(status().isNotFound())        .andExpect(jsonPath("$.message").value("Отзыв с id 1 не найден!"));  }}